// src/services/friendNotifService.ts
import { db } from '../db';
import { sendPush } from './pushDispatcher';

const TIER_PRIORITY: any = { best: 100, ultra: 80, great: 60, good: 40 };

export async function sendFriendNotification(senderId: string, recipientId: string, actionType: string, payload: any) {
  return db.tx(async tx => {
    const today = new Date().toISOString().slice(0, 10);
    const throttle = await tx.oneOrNone('SELECT * FROM friend_notif_throttle WHERE sender_id=$1 AND recipient_id=$2 AND date=$3 FOR UPDATE', [senderId, recipientId, today]);
    if (throttle && throttle.sent_count >= 2) return { throttled: true };
    const friendship = await tx.oneOrNone('SELECT tier FROM friendships WHERE LEAST(player_a, player_b)=$1 AND GREATEST(player_a, player_b)=$2', [senderId < recipientId ? senderId : recipientId, senderId > recipientId ? senderId : recipientId]);
    if (!friendship) return { not_friends: true };
    const recentSameSender = await tx.oneOrNone('SELECT id, bundled_count FROM friend_notification_log WHERE sender_id=$1 AND recipient_id=$2 AND sent_at > NOW() - INTERVAL '30 minutes' AND opened_at IS NULL', [senderId, recipientId]);
    if (recentSameSender) {
      await tx.none('UPDATE friend_notification_log SET bundled_count = bundled_count + 1, last_action_type=$1 WHERE id=$2', [actionType, recentSameSender.id]);
      await sendPush(recipientId, { title: payload.sender_name, body: `${payload.sender_name} sent ${recentSameSender.bundled_count + 1} ${actionType}s`, priority: TIER_PRIORITY[friendship.tier] || 40, image_url: payload.sender_avatar });
      return { bundled: true };
    }
    await tx.none('INSERT INTO friend_notification_log(sender_id, recipient_id, action_type, bundled_count) VALUES ($1,$2,$3,1)', [senderId, recipientId, actionType]);
    await tx.none('INSERT INTO friend_notif_throttle(sender_id, recipient_id, date, sent_count, last_sent_at) VALUES ($1,$2,$3,1,NOW()) ON CONFLICT (sender_id, recipient_id, date) DO UPDATE SET sent_count = friend_notif_throttle.sent_count + 1, last_sent_at = NOW()', [senderId, recipientId, today]);
    const personalizedBody = personalizeMessage(actionType, payload, friendship.tier);
    await sendPush(recipientId, { title: payload.sender_name, body: personalizedBody, priority: TIER_PRIORITY[friendship.tier] || 40, image_url: payload.sender_avatar });
    return { sent: true };
  });
}

function personalizeMessage(action: string, payload: any, tier: string): string {
  const tierPrefix = tier === 'best' ? `Your best friend ` : '';
  switch (action) {
    case 'battle_invite': return `${tierPrefix}wants to battle you`;
    case 'gift': return `${tierPrefix}sent you a gift`;
    case 'raid_join': return `${tierPrefix}joined your raid`;
    default: return `${tierPrefix}sent you a ${action}`;
  }
}

