// src/services/questChainService.ts
import { db } from '../db';
export async function makeChoice(playerId: string, chainId: string, choiceIdx: number) {
  return db.tx(async tx => {
    const p = await tx.one('SELECT * FROM player_chain_progress WHERE player_id=$1 AND chain_id=$2 FOR UPDATE', [playerId, chainId]);
    if (p.chapter_unlocks_at && new Date(p.chapter_unlocks_at) > new Date()) throw new Error('chapter_not_unlocked');
    const chapter = await tx.one('SELECT * FROM chapter_defs WHERE chain_id=$1 AND chapter_num=$2', [chainId, p.current_chapter]);
    if (choiceIdx >= chapter.choices.length) throw new Error('invalid_choice');
    const newChoices = [...p.choices_made, choiceIdx];
    const nextChapter = p.current_chapter + 1;
    const totalChapters = await tx.one('SELECT chapters_total FROM quest_chains WHERE id=$1', [chainId]);
    if (nextChapter > totalChapters.chapters_total) {
      await tx.none('UPDATE player_chain_progress SET choices_made=$1, completed_at=NOW() WHERE player_id=$2 AND chain_id=$3', [newChoices, playerId, chainId]);
      const ending = computeEnding(newChoices);
      await grantChainCompletion(tx, playerId, chainId, ending);
      return { completed: true, ending };
    }
    const unlocksAt = new Date(Date.now() + 18 * 3600 * 1000);
    await tx.none('UPDATE player_chain_progress SET current_chapter=$1, choices_made=$2, chapter_unlocks_at=$3 WHERE player_id=$4 AND chain_id=$5', [nextChapter, newChoices, unlocksAt, playerId, chainId]);
    return { nextChapter, unlocksAt };
  });
}
function computeEnding(choices: number[]): string {
  const sum = choices.reduce((s, c) => s + c, 0);
  if (sum < choices.length * 0.5) return 'hero';
  if (sum > choices.length * 1.5) return 'villain';
  return 'neutral';
}
async function grantChainCompletion(tx: any, playerId: string, chainId: string, ending: string) { await tx.none('INSERT INTO player_titles(player_id, title_code) VALUES ($1, $2) ON CONFLICT DO NOTHING', [playerId, `chain_${chainId}_${ending}`]); }

