import useSWR from 'swr';
import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
export function QuestChainView({ chainId, playerId }: any) {
  const { data, mutate } = useSWR(`/api/chains/${chainId}/me`, u => fetch(u).then(r => r.json()));
  const [showChoice, setShowChoice] = useState(false);
  const [timeLeft, setTimeLeft] = useState('');
  useEffect(() => {
    if (!data?.chapter_unlocks_at) return;
    const tick = () => {
      const ms = new Date(data.chapter_unlocks_at).getTime() - Date.now();
      if (ms <= 0) { setTimeLeft('READY'); mutate(); return; }
      const h = Math.floor(ms / 3600000); const m = Math.floor((ms % 3600000) / 60000);
      setTimeLeft(`${h}h ${m}m`);
    };
    tick(); const id = setInterval(tick, 1000); return () => clearInterval(id);
  }, [data]);
  if (!data) return null;
