  return (
    <div className='max-w-3xl mx-auto p-6'>
      <div className='flex items-center gap-3 mb-6 overflow-x-auto'>
        {[...Array(data.chapters_total)].map((_, i) => (
          <div key={i} className={`flex flex-col items-center min-w-[80px] ${i + 1 === data.current_chapter ? 'opacity-100' : i + 1 < data.current_chapter ? 'opacity-100' : 'opacity-30'}`}>
