        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className='p-6 bg-gradient-to-br from-slate-900 to-slate-950 rounded-xl border border-cyan-500/30'>
          <div className='text-xs uppercase tracking-widest text-cyan-400'>Chapter {data.current_chapter}</div>
