// src/services/raidLootService.ts
import { db } from '../db';
import { mulberry32, hashSeed } from '../lib/prng';

export async function distributeBossLoot(raidId: string, bossId: string, participants: string[]) {
  return db.tx(async tx => {
    const kill = await tx.one('INSERT INTO raid_kills(raid_id, boss_id, participants) VALUES ($1,$2,$3) RETURNING *', [raidId, bossId, participants]);
    const bossLoot = await tx.one('SELECT loot_pool, personal_drop_rate, group_loot_count FROM boss_loot_tables WHERE boss_id=$1', [bossId]);
    const personalDrops: any[] = [];
    for (const p of participants) {
      const playerClass = await tx.one('SELECT class FROM players WHERE id=$1', [p]);
      const seed = hashSeed(`${kill.id}:${p}`);
      const rand = mulberry32(seed);
      if (rand() < bossLoot.personal_drop_rate) {
        const classPool = bossLoot.loot_pool.filter((it: any) => it.eligible_classes.includes(playerClass.class));
        const item = classPool[Math.floor(rand() * classPool.length)];
        const loot = await tx.one('INSERT INTO raid_loot(raid_kill_id, player_id, item_id, is_personal, trade_expires_at) VALUES ($1,$2,$3,true,NOW()+INTERVAL '2 hours') RETURNING *', [kill.id, p, item.id]);
        personalDrops.push(loot);
      }
    }
    const groupItems = pickRandomItems(bossLoot.loot_pool, bossLoot.group_loot_count, () => Math.random());
    for (const item of groupItems) {
      const eligible = participants.filter(async p => {
        const cls = (await tx.one('SELECT class FROM players WHERE id=$1', [p])).class;
        return item.eligible_classes.includes(cls);
      });
      await tx.none('INSERT INTO raid_group_loot(raid_kill_id, item_id, eligible_players) VALUES ($1,$2,$3)', [kill.id, item.id, participants]);
    }
    return { personal: personalDrops, group_items: groupItems };
  });
}

export async function tradeLoot(fromId: string, lootId: string, toId: string) {
  return db.tx(async tx => {
    const loot = await tx.one('SELECT * FROM raid_loot WHERE id=$1 AND player_id=$2 FOR UPDATE', [lootId, fromId]);
    if (loot.claimed) throw new Error('already_claimed');
    if (loot.trade_expires_at < new Date()) throw new Error('trade_expired');
    const kill = await tx.one('SELECT participants FROM raid_kills WHERE id=$1', [loot.raid_kill_id]);
    if (!kill.participants.includes(toId)) throw new Error('not_in_raid');
    await tx.none('UPDATE raid_loot SET player_id=$1, traded_to=$1 WHERE id=$2', [toId, lootId]);
  });
}

export async function rollOnGroupLoot(groupLootId: string, playerId: string) {
  await db.none('INSERT INTO raid_group_loot_rolls(group_loot_id, player_id, roll) VALUES ($1, $2, $3) ON CONFLICT DO NOTHING', [groupLootId, playerId, Math.floor(Math.random() * 100) + 1]);
}
function pickRandomItems(pool: any[], n: number, rand: () => number) { return [...pool].sort(() => rand() - 0.5).slice(0, n); }

