// src/game/quadtree.ts
export class Quadtree {
  bounds: { x: number; y: number; w: number; h: number };
  capacity: number;
  entities: any[] = [];
  divided = false;
  nw?: Quadtree; ne?: Quadtree; sw?: Quadtree; se?: Quadtree;
  constructor(bounds: any, capacity = 4) { this.bounds = bounds; this.capacity = capacity; }
  insert(e: { x: number; y: number; id: string }): boolean {
    if (!this.contains(e)) return false;
    if (this.entities.length < this.capacity && !this.divided) { this.entities.push(e); return true; }
    if (!this.divided) this.subdivide();
    return this.nw!.insert(e) || this.ne!.insert(e) || this.sw!.insert(e) || this.se!.insert(e);
  }
  query(range: { x: number; y: number; w: number; h: number }, found: any[] = []): any[] {
    if (!this.intersects(range)) return found;
    for (const e of this.entities) if (this.inRange(e, range)) found.push(e);
    if (this.divided) { this.nw!.query(range, found); this.ne!.query(range, found); this.sw!.query(range, found); this.se!.query(range, found); }
    return found;
  }
  subdivide() {
    const { x, y, w, h } = this.bounds; const hw = w / 2; const hh = h / 2;
    this.nw = new Quadtree({ x, y, w: hw, h: hh }, this.capacity);
    this.ne = new Quadtree({ x: x + hw, y, w: hw, h: hh }, this.capacity);
    this.sw = new Quadtree({ x, y: y + hh, w: hw, h: hh }, this.capacity);
    this.se = new Quadtree({ x: x + hw, y: y + hh, w: hw, h: hh }, this.capacity);
    this.divided = true;
  }
  contains(e: any) { const b = this.bounds; return e.x >= b.x && e.x < b.x + b.w && e.y >= b.y && e.y < b.y + b.h; }
  intersects(r: any) { const b = this.bounds; return !(r.x + r.w < b.x || r.x > b.x + b.w || r.y + r.h < b.y || r.y > b.y + b.h); }
  inRange(e: any, r: any) { return e.x >= r.x && e.x <= r.x + r.w && e.y >= r.y && e.y <= r.y + r.h; }
}

// src/game/gameLoop.ts
import { Quadtree } from './quadtree';
import { Server } from 'socket.io';
const TICK_HZ = 30;
const VISIBILITY_RADIUS = 800;
const MAP_SIZE = 5000;

interface Entity { id: string; type: string; x: number; y: number; vx: number; vy: number; }

class GameWorld {
  entities = new Map<string, Entity>();
  lastSent = new Map<string, Set<string>>();
  constructor(private io: Server) {}
  tick() {
    const qt = new Quadtree({ x: 0, y: 0, w: MAP_SIZE, h: MAP_SIZE });
    for (const e of this.entities.values()) { e.x += e.vx / TICK_HZ; e.y += e.vy / TICK_HZ; qt.insert(e); }
    for (const [id, e] of this.entities) {
      if (e.type !== 'player') continue;
      const visible = qt.query({ x: e.x - VISIBILITY_RADIUS, y: e.y - VISIBILITY_RADIUS, w: VISIBILITY_RADIUS * 2, h: VISIBILITY_RADIUS * 2 });
      const visibleIds = new Set(visible.map((v: any) => v.id));
      const lastIds = this.lastSent.get(id) || new Set();
      const newlyVisible = visible.filter((v: any) => !lastIds.has(v.id));
      const noLongerVisible = [...lastIds].filter(lid => !visibleIds.has(lid));
      const updated = visible.filter((v: any) => lastIds.has(v.id));
      this.io.to(id).emit('state_delta', {
        full: newlyVisible.map((v: any) => ({ id: v.id, type: v.type, x: v.x, y: v.y, vx: v.vx, vy: v.vy })),
        updates: updated.map((v: any) => ({ id: v.id, x: v.x, y: v.y, vx: v.vx, vy: v.vy })),
        removed: noLongerVisible
      });
      this.lastSent.set(id, visibleIds);
    }
  }
  start() { setInterval(() => this.tick(), 1000 / TICK_HZ); }
  addPlayer(id: string, x: number, y: number) { this.entities.set(id, { id, type: 'player', x, y, vx: 0, vy: 0 }); }
  setVelocity(id: string, vx: number, vy: number) { const e = this.entities.get(id); if (e) { e.vx = vx; e.vy = vy; } }
}

