// src/game/clientLoop.ts
import { io } from 'socket.io-client';
class GameClient {
  entities = new Map<string, any>();
  socket = io();
  lastTick = Date.now();
  constructor() {
    this.socket.on('state_delta', (delta: any) => this.applyDelta(delta));
    requestAnimationFrame(() => this.render());
  }
  applyDelta(delta: any) {
    for (const e of delta.full) this.entities.set(e.id, { ...e, lastUpdate: Date.now() });
    for (const u of delta.updates) { const ex = this.entities.get(u.id); if (ex) Object.assign(ex, u, { lastUpdate: Date.now() }); }
    for (const id of delta.removed) this.entities.delete(id);
  }
  render() {
    const now = Date.now();
    const dt = (now - this.lastTick) / 1000;
    this.lastTick = now;
    for (const e of this.entities.values()) {
      e.renderX = (e.renderX ?? e.x) + (e.x + e.vx * (now - e.lastUpdate) / 1000 - (e.renderX ?? e.x)) * 0.2;
      e.renderY = (e.renderY ?? e.y) + (e.y + e.vy * (now - e.lastUpdate) / 1000 - (e.renderY ?? e.y)) * 0.2;
    }
    this.drawAll();
    requestAnimationFrame(() => this.render());
  }
  drawAll() { /* canvas draw */ }
  sendInput(vx: number, vy: number) { this.socket.emit('input', { vx, vy }); }
}

