// src/services/procTreeGenerator.ts
import { mulberry32, hashSeed } from '../lib/prng';

export interface SkillNode { id: number; parents: number[]; effect: { stat: string; multiplier: number; }; tier: number; }
export interface SkillTree { nodes: SkillNode[]; seed: string; }

const STAT_POOL = ['dps', 'crit_chance', 'gold_gain', 'xp_gain', 'health', 'speed'];

export function generateTree(seedHex: string): SkillTree {
  const seed = hashSeed(seedHex);
  const rand = mulberry32(seed);
  const nodes: SkillNode[] = [];
  for (let i = 0; i < 200; i++) {
    const tier = i === 0 ? 0 : Math.min(7, Math.floor(Math.log2(i + 1)));
    const parents = i === 0 ? [] : Array.from({ length: 1 + Math.floor(rand() * 3) }, () => Math.floor(rand() * i));
    const stat = STAT_POOL[Math.floor(rand() * STAT_POOL.length)];
    const baseMult = 1.05 + rand() * 0.15;
    nodes.push({ id: i, parents: [...new Set(parents)], effect: { stat, multiplier: baseMult * (1 + tier * 0.1) }, tier });
  }
  if (!validateNoOverpoweredSynergies(nodes)) {
    return generateTree((seed + 1).toString(16));
  }
  return { nodes, seed: seedHex };
}

function validateNoOverpoweredSynergies(nodes: SkillNode[]): boolean {
  const statTotals: Record<string, number> = {};
  for (const n of nodes) statTotals[n.effect.stat] = (statTotals[n.effect.stat] || 0) + (n.effect.multiplier - 1);
  for (const s of STAT_POOL) {
    if ((statTotals[s] || 0) > 5.0) return false;
  }
  return true;
}

export async function allocateNode(playerId: string, prestigeNum: number, nodeId: number) {
  const tree = await db.one('SELECT tree FROM player_prestige_tree WHERE player_id=$1 AND prestige_num=$2', [playerId, prestigeNum]);
  const alloc = await db.oneOrNone('SELECT allocated_node_ids FROM player_node_allocations WHERE player_id=$1 AND prestige_num=$2', [playerId, prestigeNum]);
  const node = tree.tree.nodes.find((n: any) => n.id === nodeId);
  if (!node) throw new Error('invalid_node');
  const allocated = new Set(alloc?.allocated_node_ids || []);
  if (allocated.has(nodeId)) throw new Error('already_allocated');
  if (node.parents.length > 0 && !node.parents.some((p: number) => allocated.has(p))) throw new Error('parent_not_allocated');
  await db.none(`INSERT INTO player_node_allocations(player_id, prestige_num, allocated_node_ids) VALUES ($1, $2, ARRAY[$3]) ON CONFLICT (player_id, prestige_num) DO UPDATE SET allocated_node_ids = array_append(player_node_allocations.allocated_node_ids, $3)`, [playerId, prestigeNum, nodeId]);
}

