// src/services/swissPairingService.ts
import { db } from '../db';
export async function generateRoundPairings(tournamentId: string, round: number) {
  const players = await db.any('SELECT * FROM swiss_players WHERE tournament_id=$1 ORDER BY score DESC, RANDOM()', [tournamentId]);
  const groups: Record<string, any[]> = {};
  for (const p of players) (groups[p.score] ??= []).push(p);
  const pairings: Array<[string, string]> = [];
  let carry: any[] = [];
  for (const score of Object.keys(groups).sort((a, b) => Number(b) - Number(a))) {
    let pool = [...carry, ...groups[score]];
    carry = [];
    while (pool.length >= 2) {
      const half = Math.floor(pool.length / 2);
      let topPlayer = pool[0];
      let bottomPlayer: any = null;
      let bottomIdx = half;
      for (let i = half; i < pool.length; i++) {
        if (!topPlayer.opponents_played.includes(pool[i].player_id)) { bottomPlayer = pool[i]; bottomIdx = i; break; }
      }
      if (!bottomPlayer) { for (let i = pool.length - 1; i >= 1; i--) { if (!topPlayer.opponents_played.includes(pool[i].player_id)) { bottomPlayer = pool[i]; bottomIdx = i; break; } } }
      if (!bottomPlayer) { carry.push(topPlayer); pool.shift(); continue; }
      pool.splice(bottomIdx, 1); pool.shift();
      pairings.push([topPlayer.player_id, bottomPlayer.player_id]);
    }
    carry.push(...pool);
  }
  if (carry.length === 1) {
    await db.none('UPDATE swiss_players SET score = score + 1, byes = byes + 1 WHERE tournament_id=$1 AND player_id=$2', [tournamentId, carry[0].player_id]);
  }
  for (const [a, b] of pairings) {
    await db.none('INSERT INTO swiss_matches(tournament_id, round, player_a, player_b) VALUES ($1, $2, $3, $4)', [tournamentId, round, a, b]);
  }
  return pairings;
}

export async function reportSwissResult(matchId: string, winnerId: string) {
  return db.tx(async tx => {
    const m = await tx.one('SELECT * FROM swiss_matches WHERE id=$1 FOR UPDATE', [matchId]);
    if (m.winner) throw new Error('already_reported');
    await tx.none('UPDATE swiss_matches SET winner=$1, ended_at=NOW() WHERE id=$2', [winnerId, matchId]);
    const loserId = winnerId === m.player_a ? m.player_b : m.player_a;
    await tx.none('UPDATE swiss_players SET score = score + 1, opponents_played = array_append(opponents_played, $1) WHERE tournament_id=$2 AND player_id=$3', [loserId, m.tournament_id, winnerId]);
    await tx.none('UPDATE swiss_players SET opponents_played = array_append(opponents_played, $1) WHERE tournament_id=$2 AND player_id=$3', [winnerId, m.tournament_id, loserId]);
  });
}

export async function computeBuchholz(tournamentId: string) {
  const players = await db.any('SELECT player_id, opponents_played FROM swiss_players WHERE tournament_id=$1', [tournamentId]);
  const scoreByPlayer = new Map((await db.any('SELECT player_id, score FROM swiss_players WHERE tournament_id=$1', [tournamentId])).map(p => [p.player_id, p.score]));
  for (const p of players) {
    const buchholz = p.opponents_played.reduce((s: number, opp: string) => s + (scoreByPlayer.get(opp) || 0), 0);
    await db.none('UPDATE swiss_players SET buchholz=$1 WHERE tournament_id=$2 AND player_id=$3', [buchholz, tournamentId, p.player_id]);
  }
}

