// src/services/coopMatchmaker.ts
import { redis } from '../redis';
import { db } from '../db';
export async function enqueueCoop(playerId: string, level: number, tier: number, partyId: string) {
  await redis.zadd(`coop:${tier}`, level, `${playerId}:${partyId || playerId}`);
  for (let attempt = 0; attempt < 20; attempt++) {
    const lobby = await tryFormLobby(tier, level, 4);
    if (lobby) return { lobbyId: await commitLobby(tier, lobby), members: lobby };
    await new Promise(r => setTimeout(r, 1000));
  }
  return { timedOut: true };
}
async function tryFormLobby(tier: number, anchorLevel: number, size: number) {
  const candidates = await redis.zrangebyscore(`coop:${tier}`, anchorLevel - 5, anchorLevel + 5);
  if (candidates.length < size) return null;
  const parsed = candidates.map(c => { const [p, party] = c.split(':'); return { playerId: p, partyId: party }; });
  const parties = new Map<string, string[]>();
  for (const c of parsed) { if (!parties.has(c.partyId)) parties.set(c.partyId, []); parties.get(c.partyId)!.push(c.playerId); }
  const groups = Array.from(parties.values()).sort((a, b) => a.length - b.length);
  const lobby: string[] = [];
  for (const g of groups) { if (lobby.length + g.length <= size) lobby.push(...g); if (lobby.length === size) break; }
  if (lobby.length !== size) return null;
  const levels = await Promise.all(lobby.map(async p => parseFloat((await redis.zscore(`coop:${tier}`, `${p}:${parties.get(p)}`)) || '0')));
  const mean = levels.reduce((s, x) => s + x, 0) / levels.length;
  const stdDev = Math.sqrt(levels.reduce((s, x) => s + (x - mean) ** 2, 0) / levels.length);
  if (stdDev > 5) {
    const lowestPlayer = lobby[levels.indexOf(Math.min(...levels))];
    const lowestPartyId = parsed.find(c => c.playerId === lowestPlayer)!.partyId;
    if (lowestPlayer === lowestPartyId) return null;
  }
  return lobby;
}
async function commitLobby(tier: number, members: string[]) {
  const lobby = await db.one('INSERT INTO coop_lobbies(tier, member_ids) VALUES ($1, $2) RETURNING id', [tier, members]);
  for (const m of members) await redis.zrem(`coop:${tier}`, m);
  return lobby.id;
}

