import { db } from '../db';
export async function selectGoal(playerId: string, achievementCode: string) {
  const active = await db.one('SELECT COUNT(*) FROM player_goal_selections WHERE player_id=$1', [playerId]);
  if (Number(active.count) >= 3) throw new Error('max_goals_active');
  await db.none('INSERT INTO player_goal_selections(player_id, achievement_code) VALUES ($1, $2) ON CONFLICT DO NOTHING', [playerId, achievementCode]);
}
export async function unselectGoal(playerId: string, achievementCode: string) {
  await db.none('DELETE FROM player_goal_selections WHERE player_id=$1 AND achievement_code=$2', [playerId, achievementCode]);
}
export async function grantAchievementReward(playerId: string, achievementCode: string, baseReward: number) {
  const isGoal = await db.oneOrNone('SELECT 1 FROM player_goal_selections WHERE player_id=$1 AND achievement_code=$2', [playerId, achievementCode]);
  const finalReward = isGoal ? baseReward * 2 : baseReward;
  await applyCurrencyChange({ playerId, currency: 'soft', delta: finalReward, reason: 'achievement', referenceId: achievementCode, idempotencyKey: `ach:${playerId}:${achievementCode}` });
  if (isGoal) await db.none('DELETE FROM player_goal_selections WHERE player_id=$1 AND achievement_code=$2', [playerId, achievementCode]);
}
export async function suggestNextGoal(playerId: string) {
  const pace = await db.one('SELECT AVG(progress_per_day) AS avg_pace FROM player_progress_stats WHERE player_id=$1', [playerId]);
  const candidates = await db.any(`SELECT ad.*, COALESCE(pa.progress, 0) AS progress, (ad.tiers->0->>'threshold')::numeric AS target FROM achievement_defs ad LEFT JOIN player_achievements pa ON pa.achievement_code = ad.code AND pa.player_id=$1 WHERE pa.current_tier_idx IS NULL OR pa.current_tier_idx < jsonb_array_length(ad.tiers) - 1`, [playerId]);
  const scored = candidates.map((c: any) => {
    const remaining = c.target - c.progress;
    const daysToComplete = pace.avg_pace > 0 ? remaining / pace.avg_pace : 999;
    const score = Math.abs(daysToComplete - 14);
    return { ...c, score };
  }).sort((a, b) => a.score - b.score);
  return scored.slice(0, 3);
}

