import React, { useState, useRef } from 'react';
import { View, PanResponder, StyleSheet, Dimensions, Pressable, Text } from 'react-native';
const { width, height } = Dimensions.get('window');

export function GameHUD({ onAction, onMove, handedness = 'right' }: any) {
  const joystickRef = useRef<View>(null);
  const [knobPos, setKnobPos] = useState({ x: 0, y: 0 });
  const [active, setActive] = useState(false);
  const joystickRadius = 60;
  const deadzone = joystickRadius * 0.15;
  const panResponder = PanResponder.create({
    onStartShouldSetPanResponder: () => true,
    onMoveShouldSetPanResponder: () => true,
    onPanResponderGrant: () => setActive(true),
    onPanResponderMove: (evt, gesture) => {
      const mag = Math.sqrt(gesture.dx ** 2 + gesture.dy ** 2);
      if (mag < deadzone) { setKnobPos({ x: 0, y: 0 }); onMove(0, 0); return; }
      const clampedMag = Math.min(mag, joystickRadius);
      const x = (gesture.dx / mag) * clampedMag;
      const y = (gesture.dy / mag) * clampedMag;
      setKnobPos({ x, y });
      onMove(x / joystickRadius, y / joystickRadius);
    },
    onPanResponderRelease: () => { setKnobPos({ x: 0, y: 0 }); setActive(false); onMove(0, 0); }
  });
  const joystickPosition = handedness === 'right' ? { left: 40, bottom: 40 } : { right: 40, bottom: 40 };
  const buttonsPosition = handedness === 'right' ? { right: 40, bottom: 40 } : { left: 40, bottom: 40 };
  return (
    <View pointerEvents='box-none' style={StyleSheet.absoluteFillObject}>
      <View style={[styles.joystickBase, joystickPosition, { opacity: active ? 1 : 0.5 }]} {...panResponder.panHandlers}>
        <View style={[styles.joystickKnob, { transform: [{ translateX: knobPos.x }, { translateY: knobPos.y }] }]} />
      </View>
      <View style={[styles.buttonCluster, buttonsPosition]}>
        <Pressable onPress={() => onAction('primary')} style={styles.primaryBtn}><Text style={styles.btnText}>⚔</Text></Pressable>
        <Pressable onPress={() => onAction('secondary')} style={styles.secondaryBtn}><Text style={styles.btnText}>🛡</Text></Pressable>
        <Pressable onPress={() => onAction('ability')} style={styles.abilityBtn}><Text style={styles.btnText}>★</Text></Pressable>
      </View>
    </View>
  );
}
const styles = StyleSheet.create({
  joystickBase: { position: 'absolute', width: 120, height: 120, borderRadius: 60, backgroundColor: 'rgba(255,255,255,0.1)', borderWidth: 2, borderColor: 'rgba(255,255,255,0.2)', justifyContent: 'center', alignItems: 'center' },
  joystickKnob: { width: 50, height: 50, borderRadius: 25, backgroundColor: 'rgba(255,255,255,0.8)' },
  buttonCluster: { position: 'absolute', width: 140, height: 140 },
  primaryBtn: { position: 'absolute', right: 0, bottom: 40, width: 70, height: 70, borderRadius: 35, backgroundColor: '#ef4444', justifyContent: 'center', alignItems: 'center' },
  secondaryBtn: { position: 'absolute', right: 70, bottom: 0, width: 60, height: 60, borderRadius: 30, backgroundColor: '#3b82f6', justifyContent: 'center', alignItems: 'center' },
  abilityBtn: { position: 'absolute', right: 0, bottom: 110, width: 60, height: 60, borderRadius: 30, backgroundColor: '#a855f7', justifyContent: 'center', alignItems: 'center' },
  btnText: { color: '#fff', fontSize: 28, fontWeight: '700' }
});

