// src/services/lootBoxService.ts
import { db } from '../db';
import { mulberry32, hashSeed } from '../lib/prng';
export async function openLootBox(playerId: string, boxId: string, openSeed: string) {
  return db.tx(async tx => {
    const box = await tx.one('SELECT * FROM loot_box_defs WHERE id=$1', [boxId]);
    const inventory = await tx.one('SELECT COUNT(*) FROM player_loot_boxes WHERE player_id=$1 AND box_id=$2', [playerId, boxId]);
    if (inventory.count === 0) throw new Error('no_box_to_open');
    const rand = mulberry32(hashSeed(`${playerId}:${boxId}:${openSeed}`));
    const r = rand();
    let cumulative = 0;
    let chosenItem: any = null;
    for (const item of box.contents) {
      cumulative += item.weight;
      if (r < cumulative / box.total_weight) { chosenItem = item; break; }
    }
    await tx.none('DELETE FROM player_loot_boxes WHERE id IN (SELECT id FROM player_loot_boxes WHERE player_id=$1 AND box_id=$2 LIMIT 1)', [playerId, boxId]);
    await tx.none('INSERT INTO player_items(player_id, item_code) VALUES ($1, $2)', [playerId, chosenItem.code]);
    await tx.none('INSERT INTO loot_box_openings(player_id, box_id, item_id, opened_at) VALUES ($1, $2, $3, NOW())', [playerId, boxId, chosenItem.code]);
    return { item: chosenItem, rarity: chosenItem.rarity };
  });
}

