// src/services/deviceIntegrityService.ts
import fetch from 'node-fetch';
import { db } from '../db';
import { redis } from '../redis';

export async function verifyAndroidIntegrity(integrityToken: string): Promise<any> {
  const res = await fetch('https://playintegrity.googleapis.com/v1/decode', {
    method: 'POST',
    headers: { Authorization: `Bearer ${process.env.GOOGLE_API_KEY}` },
    body: JSON.stringify({ integrityToken })
  });
  const data: any = await res.json();
  return {
    appRecognized: data.appIntegrity?.appRecognitionVerdict === 'PLAY_RECOGNIZED',
    deviceVerdict: data.deviceIntegrity?.deviceRecognitionVerdict || [],
    accountActivity: data.accountDetails?.appLicensingVerdict
  };
}

export async function verifyIosIntegrity(deviceCheckToken: string): Promise<any> {
  return { valid: true };
}

export async function processIntegrityCheck(playerId: string, deviceId: string, platform: 'android' | 'ios', token: string, extraSignals: any) {
  let verdict: any;
  if (platform === 'android') verdict = await verifyAndroidIntegrity(token);
  else verdict = await verifyIosIntegrity(token);
  const rootDetected = platform === 'android' && !verdict.deviceVerdict.includes('MEETS_DEVICE_INTEGRITY');
  const cheatToolDetected = extraSignals.processList?.some((p: string) => /gameguardian|cheat_engine|frida/i.test(p)) || false;
  const emulatorDetected = extraSignals.buildFingerprint?.includes('generic') || extraSignals.buildFingerprint?.includes('emulator') || false;
  const integrityScore = (rootDetected ? 1 : 0) + (cheatToolDetected ? 2 : 0) + (emulatorDetected ? 1 : 0);
  await db.none('INSERT INTO device_integrity_checks(device_id, player_id, check_at, safety_net_result, root_detected, cheat_tool_detected, emulator_detected) VALUES ($1, $2, NOW(), $3, $4, $5, $6)', [deviceId, playerId, JSON.stringify(verdict), rootDetected, cheatToolDetected, emulatorDetected]);
  if (integrityScore > 0) {
    await db.none('INSERT INTO player_match_pool(player_id, pool, reason) VALUES ($1, $2, $3) ON CONFLICT (player_id) DO UPDATE SET pool=$2, reason=$3, set_at=NOW()', [playerId, 'restricted', `integrity_score=${integrityScore}`]);
    await redis.sadd('match_pool:restricted', playerId);
  }
  return { restricted: integrityScore > 0 };
}

