// App.tsx — RN integrity check on launch (Android example)
import React, { useEffect } from 'react';
import { NativeModules, Platform } from 'react-native';
import DeviceInfo from 'react-native-device-info';
export function useIntegrityCheck(playerId: string) {
  useEffect(() => {
    (async () => {
      try {
        let token = '';
        if (Platform.OS === 'android') {
          token = await NativeModules.PlayIntegrity.requestToken(playerId);
        } else if (Platform.OS === 'ios') {
          token = await NativeModules.DeviceCheck.getToken();
        }
        const deviceId = await DeviceInfo.getUniqueId();
        const buildFingerprint = await DeviceInfo.getFingerprint();
        await fetch('/api/integrity/check', { method: 'POST', body: JSON.stringify({ deviceId, platform: Platform.OS, token, extraSignals: { buildFingerprint } }) });
      } catch (e) { console.error('integrity check failed', e); }
    })();
  }, [playerId]);
}

