// src/services/tournamentQuestService.ts
import { db } from '../db';
import { redis } from '../redis';
export async function earnTournamentCurrency(playerId: string, tournamentId: string, amount: number, source: string) {
  await db.tx(async tx => {
    const t = await tx.one('SELECT ends_at FROM tournaments WHERE id=$1', [tournamentId]);
    if (new Date(t.ends_at) < new Date()) throw new Error('tournament_ended');
    await tx.none('INSERT INTO player_tournament_currency(player_id, tournament_id, amount) VALUES ($1,$2,$3) ON CONFLICT (player_id, tournament_id) DO UPDATE SET amount = player_tournament_currency.amount + $3', [playerId, tournamentId, amount]);
    const newAmount = await tx.one('SELECT amount FROM player_tournament_currency WHERE player_id=$1 AND tournament_id=$2', [playerId, tournamentId]);
    await redis.zadd(`tourn:lb:${tournamentId}`, newAmount.amount, playerId);
  });
}
export async function purchaseTournamentCosmetic(playerId: string, tournamentId: string, cosmeticId: string) {
  return db.tx(async tx => {
    const cosmetic = await tx.one(`SELECT (cosmetic_pool->$2)::jsonb AS data FROM tournaments WHERE id=$1`, [tournamentId, cosmeticId]);
    const cost = cosmetic.data.cost;
    const balance = await tx.one('SELECT amount FROM player_tournament_currency WHERE player_id=$1 AND tournament_id=$2 FOR UPDATE', [playerId, tournamentId]);
    if (balance.amount < cost) throw new Error('insufficient_tournament_currency');
    await tx.none('UPDATE player_tournament_currency SET amount = amount - $1 WHERE player_id=$2 AND tournament_id=$3', [cost, playerId, tournamentId]);
    await tx.none('INSERT INTO player_cosmetics(player_id, cosmetic_code, source_tournament_id) VALUES ($1, $2, $3) ON CONFLICT DO NOTHING', [playerId, cosmeticId, tournamentId]);
  });
}
export async function endTournament(tournamentId: string) {
  await db.tx(async tx => {
    const topPlayers = await redis.zrevrange(`tourn:lb:${tournamentId}`, 0, -1, 'WITHSCORES');
    const totalPlayers = topPlayers.length / 2;
    const top1 = Math.ceil(totalPlayers * 0.01);
    const top10 = Math.ceil(totalPlayers * 0.1);
    for (let i = 0; i < topPlayers.length; i += 2) {
      const playerId = topPlayers[i];
      const rank = i / 2 + 1;
      if (rank <= top1) await tx.none('INSERT INTO player_cosmetics(player_id, cosmetic_code, source_tournament_id) VALUES ($1, $2, $3) ON CONFLICT DO NOTHING', [playerId, `tourn_${tournamentId}_top1`, tournamentId]);
      else if (rank <= top10) await tx.none('INSERT INTO player_cosmetics(player_id, cosmetic_code, source_tournament_id) VALUES ($1, $2, $3) ON CONFLICT DO NOTHING', [playerId, `tourn_${tournamentId}_top10`, tournamentId]);
      const remaining = await tx.oneOrNone('SELECT amount FROM player_tournament_currency WHERE player_id=$1 AND tournament_id=$2', [playerId, tournamentId]);
      if (remaining?.amount > 0) await tx.none(`UPDATE players SET soft_balance = soft_balance + $1 WHERE id=$2`, [Math.floor(remaining.amount * 0.5), playerId]);
    }
    await redis.del(`tourn:lb:${tournamentId}`);
  });
}

