// src/services/cardCraftingService.ts
import { db } from '../db';
const RARITY_COST: any = { common: 40, rare: 100, epic: 400, legendary: 1600 };
const DISENCHANT_RATE = 0.25;
const DAILY_CAP = 5 * 1600;

export async function disenchantCard(playerId: string, cardCode: string) {
  return db.tx(async tx => {
    const card = await tx.one('SELECT rarity FROM card_defs WHERE code=$1', [cardCode]);
    const inv = await tx.one('SELECT count FROM player_card_inventory WHERE player_id=$1 AND card_code=$2 FOR UPDATE', [playerId, cardCode]);
    if (inv.count < 1) throw new Error('not_owned');
    const dustGained = Math.floor(RARITY_COST[card.rarity] * DISENCHANT_RATE);
    await tx.none('UPDATE player_card_inventory SET count = count - 1 WHERE player_id=$1 AND card_code=$2', [playerId, cardCode]);
    await tx.none('UPDATE player_dust SET amount = amount + $1 WHERE player_id=$2', [dustGained, playerId]);
    await tx.none('INSERT INTO craft_log(player_id, action, card_code, dust_delta) VALUES ($1, $2, $3, $4)', [playerId, 'disenchant', cardCode, dustGained]);
    return { dustGained };
  });
}

export async function craftCard(playerId: string, cardCode: string) {
  return db.tx(async tx => {
    const card = await tx.one('SELECT rarity FROM card_defs WHERE code=$1', [cardCode]);
    const cost = RARITY_COST[card.rarity];
    const today = new Date().toISOString().slice(0, 10);
    const dailyCap = await tx.oneOrNone('SELECT crafts_count FROM daily_craft_cap_tracking WHERE player_id=$1 AND date=$2 FOR UPDATE', [playerId, today]);
    if ((dailyCap?.crafts_count || 0) + cost > DAILY_CAP) throw new Error('daily_cap_reached');
    const dust = await tx.one('SELECT amount FROM player_dust WHERE player_id=$1 FOR UPDATE', [playerId]);
    if (dust.amount < cost) throw new Error('insufficient_dust');
    await tx.none('UPDATE player_dust SET amount = amount - $1 WHERE player_id=$2', [cost, playerId]);
    await tx.none('INSERT INTO player_card_inventory(player_id, card_code, count) VALUES ($1, $2, 1) ON CONFLICT (player_id, card_code) DO UPDATE SET count = player_card_inventory.count + 1', [playerId, cardCode]);
    await tx.none('INSERT INTO daily_craft_cap_tracking(player_id, date, crafts_count) VALUES ($1, $2, $3) ON CONFLICT (player_id, date) DO UPDATE SET crafts_count = daily_craft_cap_tracking.crafts_count + $3', [playerId, today, cost]);
    await tx.none('INSERT INTO craft_log(player_id, action, card_code, dust_delta) VALUES ($1, $2, $3, $4)', [playerId, 'craft', cardCode, -cost]);
    return { dustSpent: cost };
  });
}

