// src/services/bigNumberService.ts
import { db } from '../db';

export function parseBigScore(s: string): { mantissa: number; exponent: number } {
  const [m, e] = s.toLowerCase().split('e');
  return { mantissa: parseFloat(m), exponent: parseInt(e || '0', 10) };
}
export function formatBigScore(mantissa: number, exponent: number): string {
  const suffixes = ['', 'K', 'M', 'B', 'T', 'Qa', 'Qi', 'Sx', 'Sp', 'Oc', 'No', 'Dc'];
  const suffixIdx = Math.floor(exponent / 3);
  if (suffixIdx < suffixes.length) {
    const displayMant = mantissa * Math.pow(10, exponent % 3);
    return `${displayMant.toFixed(2)}${suffixes[suffixIdx]}`;
  }
  return `${mantissa.toFixed(2)}e${exponent}`;
}
export function tierFromExponent(exponent: number): number { return Math.floor(exponent / 6) + 1; }
export async function updatePrestigeScore(playerId: string, mantissa: number, exponent: number) {
  const tier = tierFromExponent(exponent);
  await db.none('INSERT INTO player_prestige_score(player_id, tier, mantissa, exponent, updated_at) VALUES ($1,$2,$3,$4,NOW()) ON CONFLICT (player_id) DO UPDATE SET tier=$2, mantissa=$3, exponent=$4, updated_at=NOW()', [playerId, tier, mantissa, exponent]);
  await redis.zadd(`leaderboard:prestige:tier:${tier}`, exponent * 1000 + mantissa, playerId);
}
export async function getTierLeaderboard(tier: number, offset = 0, limit = 100) {
  const raw = await redis.zrevrange(`leaderboard:prestige:tier:${tier}`, offset, offset + limit - 1, 'WITHSCORES');
  const out: any[] = [];
