// src/services/guildWarService.ts
import { db } from '../db';
export async function declareWar(attackerGuildId: string, defenderGuildId: string, preferredSlot: number) {
  return db.tx(async tx => {
    const attacker = await tx.one('SELECT weekly_slot FROM guild_war_slots WHERE guild_id=$1', [attackerGuildId]);
    const defender = await tx.one('SELECT weekly_slot FROM guild_war_slots WHERE guild_id=$1', [defenderGuildId]);
    const overlap = attacker.weekly_slot.filter((s: number) => defender.weekly_slot.includes(s));
    if (overlap.length === 0) throw new Error('no_overlapping_slots');
    const chosen = overlap.includes(preferredSlot) ? preferredSlot : overlap[0];
    const next = nextDateForSlot(chosen);
    await detectSandbagging(tx, attackerGuildId, defenderGuildId);
    await tx.none('INSERT INTO guild_war_declarations(attacker_id, defender_id, scheduled_at, status) VALUES ($1, $2, $3, $4)', [attackerGuildId, defenderGuildId, next, 'scheduled']);
  });
}
function nextDateForSlot(slot: number): Date { /* compute next UTC date matching slot */ return new Date(); }

async function detectSandbagging(tx: any, attackerId: string, defenderId: string) {
  const ratings = await tx.one('SELECT (SELECT rating FROM guild_war_rating WHERE guild_id=$1) AS attacker, (SELECT rating FROM guild_war_rating WHERE guild_id=$2) AS defender', [attackerId, defenderId]);
  if (ratings.attacker - ratings.defender > 500) {
    const recentChange = await tx.one('SELECT AVG(member_rating_change) AS avg_change FROM guild_member_rating_log WHERE guild_id=$1 AND created_at > NOW() - INTERVAL '7 days'', [attackerId]);
    if (recentChange.avg_change < -0.2) {
      await tx.none('INSERT INTO sandbagging_review(guild_id, evidence) VALUES ($1, $2)', [attackerId, JSON.stringify({ rating_gap: ratings.attacker - ratings.defender, avg_change: recentChange.avg_change })]);
    }
  }
}

export async function reportWarResult(warId: string, scoreA: number, scoreB: number) {
  return db.tx(async tx => {
    const war = await tx.one('SELECT * FROM guild_war_declarations WHERE id=$1 FOR UPDATE', [warId]);
    if (war.status !== 'scheduled') throw new Error('invalid_state');
    const winner = scoreA > scoreB ? war.attacker_id : war.defender_id;
    await tx.none('UPDATE guild_war_declarations SET status=$1, score_a=$2, score_b=$3, winner=$4 WHERE id=$5', ['completed', scoreA, scoreB, winner, warId]);
    const aRating = await tx.one('SELECT rating FROM guild_war_rating WHERE guild_id=$1', [war.attacker_id]);
    const bRating = await tx.one('SELECT rating FROM guild_war_rating WHERE guild_id=$1', [war.defender_id]);
    const expected = 1 / (1 + Math.pow(10, (bRating.rating - aRating.rating) / 400));
    const aResult = winner === war.attacker_id ? 1 : 0;
    const aNew = aRating.rating + 32 * (aResult - expected);
    const bNew = bRating.rating + 32 * ((1 - aResult) - (1 - expected));
    await tx.none('UPDATE guild_war_rating SET rating=$1, war_count = war_count + 1 WHERE guild_id=$2', [aNew, war.attacker_id]);
    await tx.none('UPDATE guild_war_rating SET rating=$1, war_count = war_count + 1 WHERE guild_id=$2', [bNew, war.defender_id]);
  });
}

