import { db } from '../db';
import { io } from '../socket';
export async function dropInventoryAsBag(playerId: string, serverId: string, deathPos: { x: number; y: number; z: number }) {
  return db.tx(async tx => {
    const inventory = await tx.any('SELECT item_code, quantity FROM player_inventory WHERE player_id=$1', [playerId]);
    const gearScore = computeGearScore(inventory);
    const despawnMinutes = gearScore > 1000 ? 60 : 30;
    const bag = await tx.one('INSERT INTO loot_bags(server_id, x, y, z, items, dropped_by, despawn_at, gear_score) VALUES ($1,$2,$3,$4,$5,$6, NOW() + $7 * INTERVAL '1 minute', $8) RETURNING *', [serverId, deathPos.x, deathPos.y, deathPos.z, JSON.stringify(inventory), playerId, despawnMinutes, gearScore]);
    await tx.none('DELETE FROM player_inventory WHERE player_id=$1', [playerId]);
    io.to(`server:${serverId}`).emit('loot_bag_dropped', { bagId: bag.id, x: deathPos.x, y: deathPos.y, gearScore });
    return bag;
  });
}
export async function lootBag(looterId: string, bagId: string, position: { x: number; y: number }) {
  return db.tx(async tx => {
    const bag = await tx.one('SELECT * FROM loot_bags WHERE id=$1 FOR UPDATE', [bagId]);
    if (bag.despawn_at < new Date()) throw new Error('bag_despawned');
    const dist = Math.sqrt((position.x - bag.x) ** 2 + (position.y - bag.y) ** 2);
    if (dist > 5) throw new Error('too_far');
    for (const item of bag.items) {
      await tx.none('INSERT INTO player_inventory(player_id, item_code, quantity) VALUES ($1, $2, $3) ON CONFLICT (player_id, item_code) DO UPDATE SET quantity = player_inventory.quantity + $3', [looterId, item.item_code, item.quantity]);
    }
    await tx.none('DELETE FROM loot_bags WHERE id=$1', [bagId]);
    io.to(`server:${bag.server_id}`).emit('loot_bag_taken', { bagId });
    return { items: bag.items };
  });
}
function computeGearScore(inventory: any[]) { return inventory.reduce((s, i) => s + (i.quantity * 10), 0); }

