// src/services/bundleService.ts
import { db } from '../db';
import { applyCurrencyChange } from './economyService';
export async function getBundlePriceForPlayer(playerId: string, bundleId: string) {
  const bundle = await db.one('SELECT * FROM bundles WHERE id=$1', [bundleId]);
  const owned = await db.any('SELECT cosmetic_code FROM player_cosmetics WHERE player_id=$1 AND cosmetic_code = ANY($2)', [playerId, bundle.cosmetic_codes]);
  const ownedSet = new Set(owned.map(o => o.cosmetic_code));
  const totalValue = bundle.individual_values.reduce((s: number, v: number) => s + v, 0);
  const ownedValue = bundle.cosmetic_codes.reduce((s: number, code: string, i: number) => s + (ownedSet.has(code) ? bundle.individual_values[i] : 0), 0);
  const discountPct = totalValue > 0 ? ownedValue / totalValue : 0;
  return { basePrice: bundle.base_price, finalPrice: Math.floor(bundle.base_price * (1 - discountPct)), discountPct, ownedFromBundle: [...ownedSet] };
}
export async function purchaseBundle(playerId: string, bundleId: string) {
  return db.tx(async tx => {
    const pricing = await getBundlePriceForPlayer(playerId, bundleId);
    const bundle = await tx.one('SELECT * FROM bundles WHERE id=$1', [bundleId]);
    await applyCurrencyChange({ playerId, currency: 'hard', delta: -pricing.finalPrice, reason: 'bundle_purchase', referenceId: bundleId, idempotencyKey: `bundle:${playerId}:${bundleId}` });
    let refund = 0;
    for (let i = 0; i < bundle.cosmetic_codes.length; i++) {
      const code = bundle.cosmetic_codes[i];
      if (pricing.ownedFromBundle.includes(code)) { refund += bundle.individual_values[i]; continue; }
      await tx.none('INSERT INTO player_cosmetics(player_id, cosmetic_code) VALUES ($1, $2) ON CONFLICT DO NOTHING', [playerId, code]);
    }
    if (refund > 0) await applyCurrencyChange({ playerId, currency: 'hard', delta: refund, reason: 'bundle_duplicate_refund', referenceId: bundleId, idempotencyKey: `bundle:${playerId}:${bundleId}:refund` });
    return { paid: pricing.finalPrice, refunded: refund };
  });
}

