// src/game/lockstepBroker.ts
import { Server } from 'socket.io';
interface MatchState { matchId: string; tick: number; pendingInputs: Map<number, Map<string, any[]>>; players: string[]; seed: number; }
class LockstepBroker {
  matches = new Map<string, MatchState>();
  constructor(private io: Server) { setInterval(() => this.tickAll(), 100); }
  startMatch(matchId: string, players: string[], seed: number) {
    this.matches.set(matchId, { matchId, tick: 0, pendingInputs: new Map(), players, seed });
    this.io.to(`match:${matchId}`).emit('match_start', { matchId, seed, players });
  }
  receiveInput(matchId: string, playerId: string, tick: number, input: any) {
    const m = this.matches.get(matchId); if (!m) return;
    if (!m.pendingInputs.has(tick)) m.pendingInputs.set(tick, new Map());
    const inputs = m.pendingInputs.get(tick)!;
    if (!inputs.has(playerId)) inputs.set(playerId, []);
    inputs.get(playerId)!.push(input);
  }
  tickAll() {
    for (const m of this.matches.values()) {
      const upcomingTick = m.tick + 10;
      const inputs = m.pendingInputs.get(upcomingTick) || new Map();
      const tickPayload: any = { tick: upcomingTick, inputs: {} };
      for (const p of m.players) tickPayload.inputs[p] = inputs.get(p) || [];
      this.io.to(`match:${m.matchId}`).emit('tick_inputs', tickPayload);
      m.tick += 1;
      m.pendingInputs.delete(upcomingTick);
    }
  }
}

