// src/game/lockstepClient.ts
import { io as ioClient } from 'socket.io-client';
import { xorshift128plus } from '../shared/prng';
import { simulateTick } from '../shared/simulation';
class LockstepClient {
  socket = ioClient();
  matchId: string = '';
  state: any = null;
  tickBuffer: any[] = [];
  currentTick = 0;
  rand: () => number = Math.random;
  init(matchId: string) {
    this.matchId = matchId;
    this.socket.on('match_start', (data: any) => { this.rand = xorshift128plus(BigInt(data.seed)); this.state = initialState(data.players, this.rand); });
    this.socket.on('tick_inputs', (payload: any) => this.tickBuffer.push(payload));
    setInterval(() => this.advance(), 100);
  }
  advance() {
    if (this.tickBuffer.length === 0) return;
    const next = this.tickBuffer.shift();
    this.state = simulateTick(this.state, next.inputs, this.rand);
    this.currentTick = next.tick;
    const hash = hashState(this.state);
    this.socket.emit('tick_hash', { matchId: this.matchId, tick: this.currentTick, hash });
  }
  sendInput(input: any) { this.socket.emit('input', { matchId: this.matchId, tick: this.currentTick + 10, input }); }
}
function initialState(players: string[], rand: () => number) { return { units: [], rand }; }
function hashState(s: any) { return JSON.stringify(s).length; }

