// src/jobs/matchAnalyzer.ts
import { Worker } from 'bullmq';
import { db } from '../db';
import { s3 } from '../aws';

new Worker('match-analyzer', async job => {
  const { matchId } = job.data;
  const replay = await db.one('SELECT s3_url FROM match_replays WHERE match_id=$1', [matchId]);
  const obj = await s3.getObject({ Bucket: 'replays', Key: replay.s3_url }).promise();
  const events: any[] = JSON.parse(obj.Body!.toString());
  const players = await db.any('SELECT player_id FROM match_players WHERE match_id=$1', [matchId]);
  for (const p of players) {
    const keyMoments = detectKeyMoments(events, p.player_id);
    const heatmap = buildHeatmap(events, p.player_id);
    const defeat = findMomentOfDefeat(events, p.player_id);
    await db.none('INSERT INTO player_match_analysis(match_id, player_id, key_moments, heatmap, moment_of_defeat) VALUES ($1, $2, $3, $4, $5)', [matchId, p.player_id, JSON.stringify(keyMoments), JSON.stringify(heatmap), JSON.stringify(defeat)]);
  }
});

function detectKeyMoments(events: any[], playerId: string): any[] {
  const goldOverTime = events.filter(e => e.type === 'gold_change' && e.player === playerId).map(e => ({ t: e.t, gold: e.amount }));
  const moments: any[] = [];
  for (let i = 1; i < goldOverTime.length - 1; i++) {
    const delta = goldOverTime[i + 1].gold - goldOverTime[i - 1].gold;
    if (Math.abs(delta) > 500) moments.push({ t: goldOverTime[i].t, type: delta > 0 ? 'gold_spike' : 'gold_loss', delta });
  }
  return moments.slice(0, 10);
}

function buildHeatmap(events: any[], playerId: string): number[][] {
  const grid: number[][] = Array.from({ length: 50 }, () => Array(50).fill(0));
  for (const e of events) {
    if (e.type !== 'position' || e.player !== playerId) continue;
    const gx = Math.min(49, Math.floor((e.x / 1000) * 50));
    const gy = Math.min(49, Math.floor((e.y / 1000) * 50));
    grid[gy][gx] += 1;
  }
  return grid;
}

function findMomentOfDefeat(events: any[], playerId: string): any {
  const goldDiff: any[] = [];
  let myGold = 0, oppGold = 0;
  for (const e of events) {
    if (e.type === 'gold_change') { if (e.player === playerId) myGold += e.amount; else oppGold += e.amount; goldDiff.push({ t: e.t, diff: myGold - oppGold }); }
  }
  let maxSwing = 0; let swingT = 0;
  for (let i = 0; i < goldDiff.length - 1; i++) {
    const swing = goldDiff[i].diff - goldDiff[Math.min(i + 60, goldDiff.length - 1)].diff;
    if (swing > maxSwing) { maxSwing = swing; swingT = goldDiff[i].t; }
  }
  return { t: swingT, swingAmount: maxSwing };
}

