// src/services/fightingMatchmaker.ts
import { redis } from '../redis';
async function pingTest(playerA: string, playerB: string): Promise<{ avg: number; stdDev: number }> {
  const samples: number[] = [];
  for (let i = 0; i < 10; i++) { const s = await measurePing(playerA, playerB); samples.push(s); }
  const avg = samples.reduce((a, b) => a + b, 0) / samples.length;
  const stdDev = Math.sqrt(samples.reduce((s, x) => s + (x - avg) ** 2, 0) / samples.length);
  return { avg, stdDev };
}
async function measurePing(a: string, b: string): Promise<number> { return Math.random() * 200; }

export async function queueFightingMatch(playerId: string, rating: number, region: string) {
  await redis.zadd(`fg:queue:${region}`, rating, playerId);
  const startMs = Date.now();
  while (Date.now() - startMs < 30000) {
    const elapsed = (Date.now() - startMs) / 1000;
    const ratingWindow = elapsed < 10 ? 50 : elapsed < 20 ? 100 : 200;
    const pingMax = elapsed < 10 ? 80 : elapsed < 20 ? 120 : 250;
    const candidates = await redis.zrangebyscore(`fg:queue:${region}`, rating - ratingWindow, rating + ratingWindow);
    for (const c of candidates.filter(x => x !== playerId)) {
      const ping = await pingTest(playerId, c);
      if (ping.avg < pingMax && ping.stdDev < 15) {
        await redis.zrem(`fg:queue:${region}`, playerId);
        await redis.zrem(`fg:queue:${region}`, c);
        return { matched: c, ping: ping.avg };
      }
    }
    await new Promise(r => setTimeout(r, 1000));
  }
  await redis.zrem(`fg:queue:${region}`, playerId);
  return { timedOut: true };
}

