// src/services/galaxyGenerator.ts
import { mulberry32, hashSeed } from '../lib/prng';
export interface StarSystem { x: bigint; y: bigint; z: bigint; seed: number; starType: string; planets: Planet[]; isAnomaly: boolean; }
export interface Planet { name: string; biomes: string[]; atmosphere: string; gravity: number; seed: number; }
const STAR_TYPES = ['M', 'K', 'G', 'F', 'A', 'B', 'O', 'NeutronStar', 'BlackHole'];
const BIOMES = ['desert', 'forest', 'ocean', 'arctic', 'volcanic', 'toxic', 'lush'];

export function generateSystem(x: bigint, y: bigint, z: bigint): StarSystem {
  const seed = hashSeed(`${x}:${y}:${z}`);
  const rand = mulberry32(seed);
  const starType = STAR_TYPES[Math.floor(rand() * STAR_TYPES.length)];
  const planetCount = Math.floor(rand() * 8) + 1;
  const planets: Planet[] = [];
  for (let i = 0; i < planetCount; i++) {
    const pSeed = hashSeed(`${seed}:${i}`);
    const pRand = mulberry32(pSeed);
    const tempBand = pRand();
    const primaryBiome = tempBand < 0.3 ? 'arctic' : tempBand < 0.7 ? (pRand() < 0.5 ? 'forest' : 'desert') : 'volcanic';
    const secondaryBiome = ['ocean', primaryBiome === 'arctic' ? 'arctic' : 'lush', primaryBiome === 'volcanic' ? 'desert' : 'forest'][Math.floor(pRand() * 3)];
    planets.push({ name: generatePlanetName(pRand), biomes: [primaryBiome, secondaryBiome], atmosphere: pRand() < 0.6 ? 'breathable' : 'toxic', gravity: 0.5 + pRand() * 2, seed: pSeed });
  }
  const isAnomaly = checkAnomaly(x, y, z);
  return { x, y, z, seed, starType, planets, isAnomaly };
}
function checkAnomaly(x: bigint, y: bigint, z: bigint): boolean {
  const hash = Number((x * 31337n + y * 73n + z) % 1000n);
  return hash === 0;
}
const SYLLABLES = ['ka','to','mi','ze','vo','ru','ny','la','si','do'];
function generatePlanetName(rand: () => number): string {
  const len = 2 + Math.floor(rand() * 3);
  let n = '';
  for (let i = 0; i < len; i++) n += SYLLABLES[Math.floor(rand() * SYLLABLES.length)];
  return n.charAt(0).toUpperCase() + n.slice(1);
}
export async function recordDiscovery(playerId: string, x: bigint, y: bigint, z: bigint) {
  await db.none('INSERT INTO discovered_systems(player_id, x, y, z, discovered_at) VALUES ($1,$2,$3,$4,NOW()) ON CONFLICT (x, y, z) DO NOTHING', [playerId, x.toString(), y.toString(), z.toString()]);
}

