// src/three/ParticleSystem.ts
import * as THREE from 'three';
export class ParticleSystem extends THREE.InstancedMesh {
  capacity: number;
  particles: { px: number; py: number; pz: number; vx: number; vy: number; vz: number; age: number; lifetime: number; active: boolean; }[];
  startSize: number; endSize: number;
  startColor: THREE.Color; endColor: THREE.Color;
  gravity: number;
  constructor(capacity = 10000, config: any = {}) {
    const geom = new THREE.PlaneGeometry(0.1, 0.1);
    const mat = new THREE.MeshBasicMaterial({ transparent: true, depthWrite: false, blending: THREE.AdditiveBlending });
    super(geom, mat, capacity);
    this.capacity = capacity;
    this.particles = Array.from({ length: capacity }, () => ({ px: 0, py: 0, pz: 0, vx: 0, vy: 0, vz: 0, age: 0, lifetime: 1, active: false }));
    this.startSize = config.startSize || 1;
    this.endSize = config.endSize || 0;
    this.startColor = new THREE.Color(config.startColor || 0xffffff);
    this.endColor = new THREE.Color(config.endColor || 0xff0000);
    this.gravity = config.gravity || 0;
  }
  emit(count: number, origin: THREE.Vector3, velocityRange: number, lifetime: number) {
    let emitted = 0;
    for (let i = 0; i < this.capacity && emitted < count; i++) {
      if (this.particles[i].active) continue;
      const p = this.particles[i];
      p.px = origin.x; p.py = origin.y; p.pz = origin.z;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = Math.random() * velocityRange;
      p.vx = r * Math.sin(phi) * Math.cos(theta);
      p.vy = r * Math.sin(phi) * Math.sin(theta);
      p.vz = r * Math.cos(phi);
      p.age = 0;
      p.lifetime = lifetime;
      p.active = true;
      emitted++;
    }
  }
  update(dt: number) {
    const matrix = new THREE.Matrix4();
    const color = new THREE.Color();
    for (let i = 0; i < this.capacity; i++) {
      const p = this.particles[i];
      if (!p.active) { matrix.makeScale(0, 0, 0); this.setMatrixAt(i, matrix); continue; }
      p.age += dt;
      if (p.age >= p.lifetime) { p.active = false; matrix.makeScale(0, 0, 0); this.setMatrixAt(i, matrix); continue; }
      p.vy += this.gravity * dt;
      p.px += p.vx * dt; p.py += p.vy * dt; p.pz += p.vz * dt;
      const t = p.age / p.lifetime;
      const size = this.startSize + (this.endSize - this.startSize) * t;
      matrix.makeScale(size, size, size);
      matrix.setPosition(p.px, p.py, p.pz);
      this.setMatrixAt(i, matrix);
      color.copy(this.startColor).lerp(this.endColor, t);
      this.setColorAt(i, color);
    }
    this.instanceMatrix.needsUpdate = true;
    if (this.instanceColor) this.instanceColor.needsUpdate = true;
  }
}

// Usage in a R3F scene:
import { useFrame, useThree } from '@react-three/fiber';
import { useRef, useEffect } from 'react';
export function ImpactParticles({ trigger, origin }: any) {
  const ref = useRef<ParticleSystem>(null);
  const { scene } = useThree();
  useEffect(() => {
    ref.current = new ParticleSystem(2000, { startColor: 0xffaa00, endColor: 0xff0000, startSize: 0.3, endSize: 0, gravity: -2 });
    scene.add(ref.current);
    return () => { if (ref.current) scene.remove(ref.current); };
  }, [scene]);
  useEffect(() => { if (trigger && ref.current) ref.current.emit(200, origin, 5, 1.5); }, [trigger]);
  useFrame((_, delta) => { if (ref.current) ref.current.update(delta); });
  return null;
}

