// src/services/biometricService.ts
import { db } from '../db';
function extractFeatures(telemetry: any[]): number[] {
  const accelerations: number[] = [];
  const clickDeltas: number[] = [];
  for (let i = 1; i < telemetry.length; i++) {
    if (telemetry[i].type === 'mousemove' && telemetry[i-1].type === 'mousemove') {
      const dt = telemetry[i].t - telemetry[i-1].t;
      const dx = telemetry[i].x - telemetry[i-1].x;
      const dy = telemetry[i].y - telemetry[i-1].y;
      accelerations.push(Math.sqrt(dx*dx + dy*dy) / Math.max(dt, 1));
    }
    if (telemetry[i].type === 'click' && telemetry[i-1].type === 'click') clickDeltas.push(telemetry[i].t - telemetry[i-1].t);
  }
  const accMean = accelerations.reduce((s, x) => s + x, 0) / Math.max(accelerations.length, 1);
  const accStd = Math.sqrt(accelerations.reduce((s, x) => s + (x - accMean) ** 2, 0) / Math.max(accelerations.length, 1));
  const clickMean = clickDeltas.reduce((s, x) => s + x, 0) / Math.max(clickDeltas.length, 1);
  const clickStd = Math.sqrt(clickDeltas.reduce((s, x) => s + (x - clickMean) ** 2, 0) / Math.max(clickDeltas.length, 1));
  return [accMean, accStd, clickMean, clickStd, ...Array(46).fill(0)];
}

function mahalanobis(x: number[], mean: number[], invCov: number[][]): number {
  const d = x.map((v, i) => v - mean[i]);
  let sum = 0;
  for (let i = 0; i < d.length; i++) for (let j = 0; j < d.length; j++) sum += d[i] * invCov[i][j] * d[j];
  return Math.sqrt(Math.max(0, sum));
}

export async function processSessionBiometric(playerId: string, sessionId: string, telemetry: any[]) {
  const features = extractFeatures(telemetry);
  const baseline = await db.oneOrNone('SELECT baseline_vector, baseline_covariance, session_count FROM player_biometric WHERE player_id=$1', [playerId]);
  if (!baseline) {
    await db.none('INSERT INTO player_biometric(player_id, baseline_vector, session_count) VALUES ($1, $2, 1)', [playerId, features]);
    return { distance: 0, newPlayer: true };
  }
  const invCov = JSON.parse(JSON.stringify(baseline.baseline_covariance || identityMatrix(50)));
  const dist = mahalanobis(features, baseline.baseline_vector, invCov);
  await db.none('INSERT INTO session_biometric(player_id, session_id, vector, distance_from_baseline) VALUES ($1, $2, $3, $4)', [playerId, sessionId, features, dist]);
  if (dist > 4 && baseline.session_count > 10) {
    await db.none('INSERT INTO biometric_review(player_id, session_id, distance, evidence) VALUES ($1, $2, $3, $4)', [playerId, sessionId, dist, JSON.stringify({ features, baseline: baseline.baseline_vector })]);
    return { distance: dist, flagged: true };
  }
  const newMean = baseline.baseline_vector.map((v: number, i: number) => (v * baseline.session_count + features[i]) / (baseline.session_count + 1));
  await db.none('UPDATE player_biometric SET baseline_vector=$1, session_count = session_count + 1, last_updated=NOW() WHERE player_id=$2', [newMean, playerId]);
  return { distance: dist };
}
function identityMatrix(n: number): number[][] { return Array.from({ length: n }, (_, i) => Array.from({ length: n }, (_, j) => i === j ? 1 : 0)); }

