// src/lib/biometricCollector.ts — collects mouse/keyboard telemetry passively
class BiometricCollector {
  events: any[] = [];
  constructor() {
    document.addEventListener('mousemove', e => this.events.push({ type: 'mousemove', x: e.clientX, y: e.clientY, t: performance.now() }));
    document.addEventListener('click', e => this.events.push({ type: 'click', x: e.clientX, y: e.clientY, t: performance.now() }));
    document.addEventListener('keydown', e => this.events.push({ type: 'keydown', key: e.key, t: performance.now() }));
    document.addEventListener('keyup', e => this.events.push({ type: 'keyup', key: e.key, t: performance.now() }));
    setInterval(() => this.flush(), 30000);
  }
  async flush() {
    if (this.events.length === 0) return;
    const batch = this.events.splice(0, this.events.length);
    if (batch.length > 5000) batch.length = 5000;
    await fetch('/api/biometric/session', { method: 'POST', body: JSON.stringify({ events: batch }) });
  }
}
export const biometricCollector = new BiometricCollector();
